import java.awt.*;
import java.awt.image.BufferedImage;
public class ClipBug {
    public static void main(String[] args) {
        BufferedImage img = new BufferedImage(200, 200, BufferedImage.TYPE_INT_RGB);
        Graphics2D g2 = img.createGraphics();
        g2.fillRect(0, 0, 200, 200);  // fill with black
        g2.setClip(50, 50, 100, 100);
        g2.setColor(Color.RED);
        g2.fillRect(0, 0, 200, 200);  // should only fill clip area
        g2.setClip(null);  // bug: clearing clip before final draw
        g2.setColor(Color.BLUE);
        g2.fillRect(0, 0, 200, 200);  // blue covers everything because clip is null
    }
}
